"""
mkt-christ commentary — Psalms 68–70
Run: python3 scripts/zc-christ-psalms-68-70.py

Key NT connections:
  Ps68:18  → Eph 4:8 (direct — Ascension leads captives, gives gifts)
  Ps69:4   → John 15:25 (direct — hated without cause)
  Ps69:9a  → John 2:17 (direct — zeal for your house)
  Ps69:9b  → Rom 15:3 (direct — reproaches of those who reproach you)
  Ps69:21  → John 19:28-29; Matt 27:34,48 (direct — sour wine at cross)
  Ps69:22-23 → Rom 11:9-10 (direct — table as snare; Israel hardening)
  Ps69:25  → Acts 1:20 (direct — Judas homestead desolate)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"68": {"1": "<p><span class=\"level\">shadow</span> <em>God shall arise, his enemies shall be scattered; and those who hate him shall flee before him!</em> The resurrection is God arising: <em>God raised him up, loosing the pangs of death, because it was not possible for him to be held by it</em> (Acts 2:24). Death and its author scatter before the risen Christ — <em>he disarmed the rulers and authorities</em> (Col 2:15), routing them as the enemies flee at God's arising.</p>", "2": "<p><span class=\"level\">shadow</span> <em>As smoke is driven away, so you shall drive them away; as wax melts before fire, so the wicked shall perish before God!</em> The wicked melting before God — eschatological imagery: <em>every valley shall be filled, and every mountain and hill shall be made low</em> (Luke 3:5); <em>the elements will melt with fervent heat</em> (2 Pet 3:10). The wicked who opposed Christ are driven away at his vindication.</p>", "3": "<p><span class=\"level\">shadow</span> <em>But the righteous shall be glad; they shall exult before God; they shall be jubilant with joy!</em> The joy of the resurrection community: <em>though you have not seen him, you love him. Though you do not now see him, you believe in him and rejoice with joy that is inexpressible and filled with glory</em> (1 Pet 1:8). The righteous exult before God through Christ who is their righteousness (Phil 3:9).</p>", "4": "<p><span class=\"level\">shadow</span> <em>Sing to God, sing praises to his name; lift up a song to him who rides through the deserts; his name is the LORD; exult before him!</em> The one who rides through the deserts is the rider on the white horse (Rev 19:11-16) — Christ whose name is the Word of God (Rev 19:13). The LORD whose name is lifted up is the Lord Jesus, at whose name every knee bows (Phil 2:9-10).</p>", "5": "<p><span class=\"level\">revelation of God</span> <em>Father of the fatherless and protector of widows is God in his holy habitation.</em> God's fatherly care for the vulnerable is most fully revealed in Christ, who ministered to the widow of Nain (Luke 7:11-15), honored the widow's offering (Luke 21:1-4), and entrusted his mother to the beloved disciple from the cross (John 19:26-27). James grounds care for orphans and widows in God's holy character (James 1:27).</p>", "6": "<p><span class=\"level\">shadow</span> <em>God settles the solitary in a home; he leads out the prisoners to prosperity, but the rebellious dwell in a parched land.</em> Christ's Nazareth sermon cites Isaiah's prisoner-release as his own mission: <em>he has sent me to proclaim liberty to the captives and recovering of sight to the blind, to set at liberty those who are oppressed</em> (Luke 4:18, citing Isa 61:1). The Ascension text in Eph 4:8 connects to v18 of this psalm — the same liberating theme.</p>", "7": "<p><span class=\"level\">type</span> <em>O God, when you went out before your people, when you marched through the wilderness,</em> The Exodus march prefigures Christ leading his people through the wilderness of this age. Paul identifies the wilderness generation's experience with Christ: <em>they drank from the spiritual Rock that followed them, and the Rock was Christ</em> (1 Cor 10:4). The divine march through the wilderness is Christ's own pattern of faithfulness through suffering.</p>", "8": "<p><span class=\"level\">type</span> <em>the earth quaked, the heavens poured down rain, before God, the One of Sinai, before God, the God of Israel.</em> Sinai's theophany — quaking, rain, fire — is the pattern the NT applies to the Passion and Parousia: earthquake at the crucifixion (Matt 27:51), fire at Pentecost (Acts 2:3), cosmic signs at the consummation (Rev 6:12-17). The God of Sinai is the God whose glory shines in the face of Christ (2 Cor 4:6).</p>", "9": "<p><span class=\"level\">type</span> <em>Rain in abundance, O God, you shed abroad; you restored your inheritance as it languished;</em> The abundant rain as divine provision — the Spirit poured out at Pentecost like rain: <em>in the last days... I will pour out my Spirit on all flesh</em> (Acts 2:17, citing Joel 2:28). Christ restores the languishing inheritance by sending the Spirit of adoption (Gal 4:6) to renew God's people.</p>", "10": "<p><span class=\"level\">shadow</span> <em>your flock found a dwelling in it; in your goodness, O God, you provided for the needy.</em> Christ the Good Shepherd provides for the needy flock: <em>I am the good shepherd... I lay down my life for the sheep</em> (John 10:11). The dwelling the flock finds is the Father's house: <em>in my Father's house are many rooms... I go to prepare a place for you</em> (John 14:2).</p>", "11": "<p><span class=\"level\">shadow</span> <em>The Lord gives the word; the women who announce the news are a great host:</em> The first proclaimers of the resurrection were women — a great host carrying the news: <em>Go quickly and tell his disciples that he has risen from the dead</em> (Matt 28:7). The Lord gives the word of resurrection and chooses women as the first heralds — the great host of those who announce the good news.</p>", "12": "<p><span class=\"level\">shadow</span> <em>The kings of the armies — they flee, they flee! — the women at home divide the spoil.</em> The kings who fled at Christ's resurrection — death, sin, the powers — are routed. The spoil divided is the grace poured out: <em>to each one of us grace was given according to the measure of Christ's gift</em> (Eph 4:7), which Paul grounds in v18 of this psalm about the Ascension and its gifts.</p>", "13": "<p><span class=\"level\">shadow</span> <em>though you men lie among the sheepfolds — the wings of a dove covered with silver, its pinions with shimmering gold.</em> The dove of peace and beauty — the Spirit descending as a dove at Christ's baptism (Matt 3:16). The shimmering silver and gold of the dove's wings reflect the transfiguration glory: <em>his clothes became radiant, intensely white</em> (Mark 9:3).</p>", "14": "<p><span class=\"level\">shadow</span> <em>When the Almighty scatters kings there, let snow fall on Zalmon.</em> The scattering of kings at the Ascension and parousia: <em>all authority in heaven and on earth has been given to me</em> (Matt 28:18). The transformation of dark mountains to gleaming snow mirrors the resurrection transformation — what was dead and dark becomes luminous under the power of God.</p>", "15": "<p><span class=\"level\">shadow</span> <em>O mountain of God, mountain of Bashan; O many-peaked mountain, mountain of Bashan!</em> The many-peaked mountain — a type of Zion, the mountain of God's presence. Christ as the new Zion: <em>you have come to Mount Zion and to the city of the living God, the heavenly Jerusalem</em> (Heb 12:22). The mountain where God dwells is now the risen Christ — the meeting place of heaven and earth.</p>", "16": "<p><span class=\"level\">shadow</span> <em>Why do you look with hatred, O many-peaked mountain, at the mount that God desired for his abode, yes, where the LORD will dwell forever?</em> God's chosen dwelling is not the impressive peaks but the humble mount — Zion, and ultimately Christ himself: <em>the one whom God has chosen and precious... a cornerstone chosen and precious</em> (1 Pet 2:4-6). The unexpected, humble mountain is where God forever dwells.</p>", "17": "<p><span class=\"level\">shadow</span> <em>The chariots of God are twice ten thousand, thousands upon thousands; the Lord is among them; Sinai is now in the sanctuary.</em> The Lord among his innumerable heavenly armies — Christ who said he could call twelve legions of angels (Matt 26:53) but chose not to. At the Ascension, Christ enters the heavenly sanctuary (Heb 9:12) where ten thousand times ten thousand angels surround the throne (Rev 5:11).</p>", "18": "<p><span class=\"level\">direct</span> <em>You ascended on high, leading a host of captives in your train and receiving gifts among men, even among the rebellious, that the LORD God may dwell there.</em> Ephesians 4:8 quotes and transforms this verse to describe Christ's Ascension: <em>When he ascended on high he led a host of captives and gave gifts to men.</em> Paul reads the Ascension as the fulfillment of this victory march — Christ ascending to the Father's right hand and distributing the Spirit's gifts to the church.</p>", "19": "<p><span class=\"level\">shadow</span> <em>Blessed be the Lord, who daily bears us up; God is our salvation.</em> Christ daily bearing his people: his continual intercession at the Father's right hand (Rom 8:34; Heb 7:25 — <em>he always lives to make intercession for them</em>). God is our salvation — Acts 4:12: <em>there is no other name under heaven given among men by which we must be saved.</em></p>", "20": "<p><span class=\"level\">shadow</span> <em>Our God is a God of salvation, and to GOD, the Lord, belong deliverances from death.</em> Deliverances from death belong supremely to the resurrection: <em>God raised him from the dead, freeing him from the agony of death, because it was impossible for death to keep its hold on him</em> (Acts 2:24). The plural <em>deliverances</em> encompasses not only Christ's resurrection but the resurrection of all who are in him.</p>", "21": "<p><span class=\"level\">shadow</span> <em>But God will strike the heads of his enemies, the hairy crown of him who walks in his guilty ways.</em> The ultimate defeat of Satan — the serpent whose head is struck: <em>the God of peace will soon crush Satan under your feet</em> (Rom 16:20). Christ crushes the head of the enemy (Gen 3:15) through the cross, where the one who walks in guilty ways against the righteous one is condemned (Col 2:15).</p>", "22": "<p><span class=\"level\">shadow</span> <em>The Lord said, I will bring them back from Bashan, I will bring them back from the depths of the sea,</em> Bringing back from the depths — the resurrection. Christ descends into the depths of death (Eph 4:9 — the lower regions of the earth) and is brought back: <em>who will descend into the abyss? (that is, to bring Christ up from the dead)</em> (Rom 10:7). From Bashan to the sea's depths, no depth is beyond the reach of resurrection.</p>", "23": "<p><span class=\"level\">shadow</span> <em>that you may strike your feet in their blood, that the tongues of your dogs may have their portion from the foe.</em> The judgment imagery of the victorious return — the eschatological battle of Revelation (Rev 19:17-21). The graphic language of victory over those who opposed the righteous one is the language of divine vindication at the last day, when the one who was rejected returns as conqueror.</p>", "24": "<p><span class=\"level\">shadow</span> <em>Your procession is seen, O God, the procession of my God, my King, into the sanctuary —</em> The triumphant procession into the sanctuary — Christ's entry into the heavenly sanctuary with his own blood: <em>he entered once for all into the holy places, not by means of the blood of goats and calves but by means of his own blood, thus securing an eternal redemption</em> (Heb 9:12). The processional into God's presence is the Ascension.</p>", "25": "<p><span class=\"level\">shadow</span> <em>the singers in front, the musicians last, between them virgins playing tambourines:</em> The worshiping procession that accompanies Christ into the sanctuary is the church — the great assembly gathered to praise. Heb 2:12 (citing Ps 22:22) shows Christ leading the praise in the midst of the congregation: he is both the processional leader and the chief singer of God's praises.</p>", "26": "<p><span class=\"level\">theme</span> <em>Bless God in the great congregation, the LORD, O you who are of Israel's fountain!</em> The great congregation blessing God — the universal church gathered in Christ. Paul's vision: <em>that together you may with one voice glorify the God and Father of our Lord Jesus Christ</em> (Rom 15:6). Israel's fountain is Christ himself — <em>from his fullness we have all received, grace upon grace</em> (John 1:16).</p>", "27": "<p><span class=\"level\">shadow</span> <em>There is Benjamin, the least of them, in the lead, the princes of Judah in their throng, the princes of Zebulun, the princes of Naphtali.</em> The unity of the tribes under God's king — fulfilled in Christ who gathers the scattered children of God into one (John 11:52). The twelve tribes assembled become the twelve apostles and the new Israel, the church drawn from every tribe (Rev 7:4-8).</p>", "28": "<p><span class=\"level\">shadow</span> <em>Summon your power, O God, the power by which you have worked for us.</em> The power of God summoned — the resurrection power: <em>what is the immeasurable greatness of his power toward us who believe, according to the working of his great might that he worked in Christ when he raised him from the dead</em> (Eph 1:19-20). The power that raised Christ is the power working for his people.</p>", "29": "<p><span class=\"level\">shadow</span> <em>Because of your temple at Jerusalem kings shall bear gifts to you.</em> The temple that draws kings to bring gifts is Christ himself — <em>I tell you, something greater than the temple is here</em> (Matt 12:6). The Magi bring gifts to the infant king (Matt 2:11); the kings of the earth bring their glory into the new Jerusalem (Rev 21:24). The universal tribute to Christ fulfills this verse.</p>", "30": "<p><span class=\"level\">shadow</span> <em>Rebuke the beasts that dwell among the reeds, the herd of bulls with the calves of the peoples. Trample underfoot those who lust after tribute; scatter the peoples who delight in war.</em> Christ rebukes the powers — the beast imagery of Revelation connects here. He tramples those who delight in war through his cross (Col 2:15) and at the parousia scatters those who wage war against the Lamb (Rev 19:19-21).</p>", "31": "<p><span class=\"level\">shadow</span> <em>Nobles shall come from Egypt; Cush shall hasten to stretch out her hands to God.</em> The nations streaming to God — Acts 8:26-40 (the Ethiopian eunuch from Cush who receives Philip's testimony and is baptized). Egypt and Cush as the ends of the earth reaching out to God finds its first fulfillment in the earliest Gentile conversions and its final fulfillment in Rev 7:9 (all nations before the throne).</p>", "32": "<p><span class=\"level\">shadow</span> <em>O kingdoms of the earth, sing to God; sing praises to the Lord,</em> The kingdoms singing to Christ — <em>the kingdom of the world has become the kingdom of our Lord and of his Christ, and he shall reign forever and ever</em> (Rev 11:15). The singing of the kingdoms anticipates the new song of the redeemed from every kingdom, tribe, and tongue (Rev 5:9).</p>", "33": "<p><span class=\"level\">revelation of God</span> <em>to him who rides in the heavens, the ancient heavens; behold, he sends out his voice, his mighty voice.</em> Christ who rides the heavens: <em>behold, he is coming with the clouds, and every eye will see him</em> (Rev 1:7). His mighty voice — the voice like the roar of many waters (Rev 1:15) that John hears at Patmos — is the voice of the one who rides through the heavens and speaks creation into being.</p>", "34": "<p><span class=\"level\">shadow</span> <em>Ascribe power to God, whose majesty is over Israel, and whose power is in the skies.</em> Ascribing power to God is ascribing power to Christ, in whom the fullness of God dwells bodily (Col 2:9). His majesty over Israel and his power in the skies is the ascended Lord's authority: <em>all authority in heaven and on earth has been given to me</em> (Matt 28:18).</p>", "35": "<p><span class=\"level\">revelation of God</span> <em>Awesome is God from his sanctuary; the God of Israel — he is the one who gives power and strength to his people. Blessed be God!</em> The God who gives power from his sanctuary is the Christ who gives the Spirit: <em>you will receive power when the Holy Spirit has come upon you</em> (Acts 1:8). The awesome God from his sanctuary is the ascended Christ at the Father's right hand, blessing his people with every spiritual blessing (Eph 1:3).</p>"}, "69": {"1": "<p><span class=\"level\">shadow</span> <em>Save me, O God! For the waters have come up to my neck.</em> The waters of chaos threatening life — the depth-imagery that Paul applies to Christ's descent: <em>who will descend into the abyss? (that is, to bring Christ up from the dead)</em> (Rom 10:7). Christ takes the drowning that the sinner deserves; the waters of judgment rise to his neck so they need not overwhelm those in him.</p>", "2": "<p><span class=\"level\">shadow</span> <em>I sink in deep mire, where there is no foothold; I have come into deep waters, and the flood sweeps over me.</em> The deep mire and flood sweeping over — the desolation of the cross where Christ is immersed in judgment. He who walked on water (Matt 14:25) sinks into the mire of human sin so that those who sink might be raised with him. The flood that swept over him is the one Noah's flood typified (1 Pet 3:20-21).</p>", "3": "<p><span class=\"level\">shadow</span> <em>I am weary with my crying out; my throat is parched. My eyes grow dim with waiting for my God.</em> The exhaustion of the cross: hours of crying out, throat parched — <em>I thirst</em> (John 19:28). Eyes growing dim waiting for God — the darkened hours of Golgotha (Matt 27:45-46) when God's presence seems withdrawn. Christ drinks the full cup of human abandonment and waits for the Father.</p>", "4": "<p><span class=\"level\">direct</span> <em>More in number than the hairs of my head are those who hate me without cause; mighty are those who would destroy me, those who attack me with lies. What I did not steal must I now restore?</em> John 15:25 cites the <em>without cause</em> motif from this psalm (and Ps 35:19): <em>they hated me without a cause</em> — Jesus applies it directly to himself. The causeless hatred, the lying accusers, the demand that he restore what he did not take: all fulfilled in the trial and crucifixion.</p>", "5": "<p><span class=\"level\">shadow</span> <em>O God, you know my folly; the wrongs I have done are not hidden from you.</em> A puzzling verse: Christ who had no folly or wrong. He speaks here as the one who has taken the position of the sinner — <em>he made him to be sin who knew no sin</em> (2 Cor 5:21). Standing in the sinner's place before God, he voices what belongs to us; God's knowledge of the wrong is answered by Christ's bearing of it.</p>", "6": "<p><span class=\"level\">shadow</span> <em>Let not those who hope in you be put to shame through me, O Lord GOD of hosts; let not those who seek you be dishonored through me, O God of Israel.</em> Christ's intercession for his own: he bears shame so that they are not put to shame. <em>Everyone who believes in him will not be put to shame</em> (Rom 10:11, citing Isa 28:16). His prayer that those who hope in God not be dishonored through his suffering is answered by the resurrection.</p>", "7": "<p><span class=\"level\">shadow</span> <em>For it is for your sake that I have borne reproach, that dishonor has covered my face.</em> Christ bore reproach for the Father's sake — Paul grounds this in v9b (Rom 15:3): Christ did not please himself but bore the reproach that fell on him for God's honor. The dishonor covering his face is the blindfolding and striking of the soldiers (Luke 22:64), the shame of the cross.</p>", "8": "<p><span class=\"level\">shadow</span> <em>I have become a stranger to my brothers, an alien to my mother's sons.</em> Christ's alienation from family: <em>not even his brothers believed in him</em> (John 7:5). He became a stranger to his own (John 1:11 — <em>he came to his own, and his own people did not receive him</em>). The estrangement of the righteous sufferer from family is Christ's actual experience in his earthly ministry.</p>", "9": "<p><span class=\"level\">direct</span> <em>For zeal for your house has consumed me, and the reproaches of those who reproach you have fallen on me.</em> Two direct citations: (1) John 2:17 — after the Temple cleansing, <em>his disciples remembered that it was written, Zeal for your house will consume me.</em> (2) Romans 15:3 — <em>For Christ did not please himself, but as it is written, The reproaches of those who reproached you fell on me.</em> Both halves of this verse are applied explicitly to Christ in the NT.</p>", "10": "<p><span class=\"level\">shadow</span> <em>When I wept and humbled my soul with fasting, it became my reproach.</em> Christ's fasting in the wilderness (Matt 4:2) and his weeping (John 11:35; Luke 19:41) — acts of genuine humility and grief that are mocked. His weeping at Lazarus's tomb caused some to mock his apparent inability to prevent death (John 11:37). Humility before God becomes the occasion for human reproach.</p>", "11": "<p><span class=\"level\">shadow</span> <em>When I made sackcloth my clothing, I became a byword to them.</em> The byword — Christ as the crucified Messiah who was a stumbling block to Jews and folly to Greeks (1 Cor 1:23). The sackcloth-wearer who is mocked is the righteous sufferer; the cross becomes the byword of shame that God transforms into the power and wisdom of God (1 Cor 1:24).</p>", "12": "<p><span class=\"level\">shadow</span> <em>I am the talk of those who sit in the gate, and the drunkards make songs about me.</em> The public mockery — at the gate (the place of judgment) and in the streets. Those who mocked Christ at the trial (Matt 26:67-68) and at the cross (Matt 27:39-44) made him the subject of their taunts. The drunkards' songs become the soldiers' mockery: <em>Hail, King of the Jews!</em></p>", "13": "<p><span class=\"level\">shadow</span> <em>But as for me, my prayer is to you, O LORD. At an acceptable time, O God, in the abundance of your steadfast love answer me in your saving faithfulness.</em> The <em>acceptable time</em> — Paul cites Isaiah's <em>in an acceptable time I have listened to you</em> (2 Cor 6:2) to describe the present age of salvation: <em>Behold, now is the acceptable time.</em> Christ's prayer is answered at the acceptable time — the resurrection on the third day.</p>", "14": "<p><span class=\"level\">shadow</span> <em>Deliver me from sinking in the mire; let me be delivered from my enemies and from the deep waters.</em> The deliverance from deep waters and mire — the resurrection is Christ's deliverance from the depths of death. <em>God raised him up, loosing the pangs of death</em> (Acts 2:24). The enemy death and the deep waters of judgment are both overcome in the resurrection of the one who prays here.</p>", "15": "<p><span class=\"level\">shadow</span> <em>Let not the flood sweep over me, or the deep swallow me up, or the pit close its mouth over me.</em> The pit closing its mouth — death sealing its claim over Christ. But the tomb cannot hold him (Acts 2:24 — <em>it was not possible for him to be held by it</em>). The pit that closed its mouth over him on Good Friday opened at the resurrection; the deep that swallowed him disgorged its conqueror.</p>", "16": "<p><span class=\"level\">revelation of God</span> <em>Answer me, O LORD, for your steadfast love is good; according to your abundant mercy, turn to me.</em> God's steadfast love (chesed) is the motivation of the atonement: <em>God so loved the world that he gave his only Son</em> (John 3:16); <em>in this is love, not that we have loved God but that he loved us and sent his Son to be the propitiation for our sins</em> (1 John 4:10). The abundant mercy that turns toward the afflicted one is made flesh in Christ.</p>", "17": "<p><span class=\"level\">shadow</span> <em>Hide not your face from your servant, for I am in distress; make haste to answer me.</em> The hidden face at the cross — <em>My God, my God, why have you forsaken me?</em> (Matt 27:46). The servant in distress is Christ who experiences the full weight of divine hiddenness so that his people need never experience it permanently. The resurrection is the face of God turned again toward the servant.</p>", "18": "<p><span class=\"level\">shadow</span> <em>Draw near to my soul, and redeem it; ransom me because of my enemies!</em> God draws near to redeem by sending the Son: <em>when the fullness of time had come, God sent forth his Son... to redeem those who were under the law</em> (Gal 4:4-5). The ransom paid is the blood of Christ — <em>the Son of Man came... to give his life as a ransom for many</em> (Matt 20:28).</p>", "19": "<p><span class=\"level\">shadow</span> <em>You know my reproach, and my shame and my dishonor; my foes are all known to you.</em> God knows the reproach Christ bore — the shame of the cross, which Christ despised but endured (Heb 12:2). The Father's knowledge of his Son's dishonor is the ground of vindication: precisely because God knows, he acts in the resurrection to reverse every shame and honor the one who was dishonored.</p>", "20": "<p><span class=\"level\">shadow</span> <em>Reproaches have broken my heart, so that I am in despair. I looked for pity, but there was none, and for comforters, but I found none.</em> The heart broken by reproach — perhaps literally (John 19:34 — blood and water from the pierced side suggests cardiac rupture). Comforters found none: disciples fled (Matt 26:56), Peter denied (Matt 26:69-75), the crowd mocked. The comfortless suffering is Christ's alone, so that he might be the Comforter through the Spirit (John 14:16).</p>", "21": "<p><span class=\"level\">direct</span> <em>They gave me poison for food, and for my thirst they gave me sour wine to drink.</em> The most direct fulfillment in the Passion: John 19:28-29 — <em>Jesus, knowing that all was now finished, said (to fulfill the Scripture), I thirst. A jar full of sour wine stood there, so they put a sponge full of the sour wine on a hyssop branch and held it to his mouth.</em> Matthew 27:34,48; Mark 15:36; Luke 23:36 all record the sour wine offered at the cross — the precise fulfillment of Psalm 69:21.</p>", "22": "<p><span class=\"level\">direct</span> <em>Let their table become a snare before them; make their sacrificial feasts a trap.</em> Romans 11:9-10 quotes verses 22-23 to explain Israel's stumbling: <em>And David says, Let their table become a snare and a trap, a stumbling block and a retribution for them.</em> Paul applies this to those who rejected Christ — the covenant blessings becoming occasions of judgment for those who refused the Messiah.</p>", "23": "<p><span class=\"level\">direct</span> <em>Let their eyes be darkened, so that they cannot see, and make their loins tremble continually.</em> Romans 11:10 continues the citation: <em>let their eyes be darkened so that they cannot see, and bend their backs forever.</em> Paul uses this verse (combined with v22) to explain the hardening of Israel that has opened the door for Gentile salvation — the stumbling of some for the fullness of others, until all Israel is saved (Rom 11:25-26).</p>", "24": "<p><span class=\"level\">shadow</span> <em>Pour out your indignation upon them, and let your burning anger overtake them.</em> The divine wrath poured out — which Christ absorbed at the cross (Rom 3:25 — God presented him as a propitiation). The indignation that should fall on the sinner fell on the righteous one; those who reject his propitiating work face the undiluted wrath (Rev 14:10).</p>", "25": "<p><span class=\"level\">direct</span> <em>May their camp be desolate; let no one dwell in their tents.</em> Acts 1:20 applies this verse directly to Judas: <em>For it is written in the Book of Psalms, Let his homestead become desolate, and let there be no one to dwell in it.</em> Peter explicitly cites Psalm 69:25 as the scriptural warrant for Judas's fate and the need to appoint a replacement.</p>", "26": "<p><span class=\"level\">shadow</span> <em>For they persecute him whom you have struck, and they recount the pain of those you have wounded.</em> Those who persecuted Christ when God struck him — the crowd that joined in the Passion, Pilate who handed him over, the soldiers who struck the already-condemned one. Paul's citation context (Rom 11) situates this in the hardening of those who would not recognize God's own Messiah in his suffering.</p>", "27": "<p><span class=\"level\">shadow</span> <em>Add to them punishment upon punishment; may they have no acquittal from you.</em> The imprecation against those who rejected the righteous one — read through Christ, this is the solemn warning of Hebrews: <em>how much worse punishment will be deserved by the one who has trampled underfoot the Son of God</em> (Heb 10:29). The no-acquittal clause is the unforgivable sin of final rejection.</p>", "28": "<p><span class=\"level\">shadow</span> <em>Let them be blotted out of the book of the living; let them not be enrolled among the righteous.</em> The book of the living — the book of life (Rev 3:5; 13:8; 20:15). Christ promises: <em>the one who conquers will be clothed thus in white garments, and I will never blot his name out of the book of life</em> (Rev 3:5). Those who reject him are not enrolled among the righteous; those who receive him have their names written permanently in the Lamb's book of life.</p>", "29": "<p><span class=\"level\">shadow</span> <em>But I am afflicted and in pain; let your salvation, O God, set me on high!</em> The afflicted and pained one set on high — the Ascension as God's answer to the lament. <em>Therefore God has highly exalted him and bestowed on him the name that is above every name</em> (Phil 2:9). The one who descended into the depths of pain is set on high above all creation.</p>", "30": "<p><span class=\"level\">shadow</span> <em>I will praise the name of God with a song; I will magnify him with thanksgiving.</em> The praise that follows deliverance — Christ leading his brothers in praise (Heb 2:12, citing Ps 22:22). The song of thanksgiving that emerges from lament is the Easter hymn — the church's praise grounded in the resurrection of the one who was in pain and is now set on high.</p>", "31": "<p><span class=\"level\">shadow</span> <em>This will please the LORD more than an ox or a bull with horns and hoofs.</em> The sacrifice God prefers over bulls and oxen — the obedient heart of Christ: <em>sacrifices and offerings you have not desired... behold, I have come to do your will</em> (Heb 10:5-7, citing Ps 40:6-8). Christ's willing self-offering pleases the Father more than all the animal sacrifices of the Levitical system combined.</p>", "32": "<p><span class=\"level\">shadow</span> <em>When the humble see it they will be glad; you who seek God, let your hearts revive.</em> The humble who see and are glad — those who receive the resurrection news: <em>but to each one of us grace was given</em> (Eph 4:7). The hearts that revive are the hearts of the disciples who see the risen Lord (John 20:20 — <em>the disciples were glad when they saw the Lord</em>).</p>", "33": "<p><span class=\"level\">revelation of God</span> <em>For the LORD hears the needy and does not despise his own people who are prisoners.</em> The God who does not despise prisoners is revealed in Christ who identifies with the prisoner: <em>I was in prison and you came to me</em> (Matt 25:36); <em>the Spirit of the Lord is upon me... to proclaim liberty to the captives</em> (Luke 4:18). He who is God does not despise his own people who are captive.</p>", "34": "<p><span class=\"level\">shadow</span> <em>Let heaven and earth praise him, the seas and everything that moves in them.</em> The universal praise directed at God through Christ — Revelation's vision: <em>every creature in heaven and on earth and under the earth and in the sea, and all that is in them, saying, To him who sits on the throne and to the Lamb be blessing and honor and glory and might forever and ever!</em> (Rev 5:13).</p>", "35": "<p><span class=\"level\">shadow</span> <em>For God will save Zion and build up the cities of Judah, and people shall dwell there and possess it;</em> The new Jerusalem built up by God through Christ — <em>I saw the holy city, new Jerusalem, coming down out of heaven from God</em> (Rev 21:2). God saves Zion not through military might but through the Lamb — the one who was slain becomes the lamp of the new city (Rev 21:23).</p>", "36": "<p><span class=\"level\">shadow</span> <em>the offspring of his servants shall inherit it, and those who love his name shall dwell in it.</em> The inheritance of the servants' offspring — the heirs of God and co-heirs with Christ (Rom 8:17). Those who love his name shall dwell in it: <em>in my Father's house are many rooms... I go to prepare a place for you</em> (John 14:2). The dwelling is prepared by the one whose name is loved — Christ, who secures the inheritance for the offspring of his servants.</p>"}, "70": {"1": "<p><span class=\"level\">shadow</span> <em>Make haste, O God, to deliver me! O LORD, make haste to help me!</em> The urgent petition — the eschatological cry of the church awaiting Christ's return: <em>Come, Lord Jesus!</em> (Rev 22:20). Christ inhabits this urgency in Gethsemane where the hour of trial comes upon him; the church prays it in his name, longing for the deliverer to hasten his coming.</p>", "2": "<p><span class=\"level\">shadow</span> <em>Let them be put to shame and confusion who seek my life! Let them be turned back and brought to dishonor who delight in my hurt!</em> The shaming of those who sought Christ's life — overturned at the resurrection. Those who delighted in his hurt at the cross are confounded by the empty tomb: <em>God raised him up, loosing the pangs of death</em> (Acts 2:24), bringing dishonor on every scheme devised against the righteous one.</p>", "3": "<p><span class=\"level\">shadow</span> <em>Let them turn back because of their shame who say, Aha, Aha!</em> The Aha! of mockery at the cross (Mark 15:29 — the crowd wagging their heads and saying <em>Aha!</em>) is the specific taunt turned back on the mockers at the resurrection. The shame they intended for Christ rebounds on those who said it, as they cannot deny the empty tomb (Matt 28:11-15).</p>", "4": "<p><span class=\"level\">shadow</span> <em>May all who seek you rejoice and be glad in you! May those who love your salvation say evermore, God is great!</em> The joy of those who seek God — the disciples' joy at the resurrection (John 20:20 — <em>the disciples were glad when they saw the Lord</em>). Those who love his salvation say evermore <em>God is great</em> — the church's doxology grounded in the resurrection, the definitive display of God's greatness.</p>", "5": "<p><span class=\"level\">shadow</span> <em>But I am poor and needy; hasten to me, O God! You are my help and my deliverer; O LORD, do not delay!</em> Christ is the poor and needy one — <em>though he was rich, yet for your sake he became poor</em> (2 Cor 8:9). From this poverty he cries for the Father to hasten, as in Gethsemane (<em>if it be possible, let this cup pass</em>, Matt 26:39). The Father hastens in resurrection; the church prays the same cry for his parousia.</p>"}}

if __name__ == "__main__":
    book = "psalms"
    source = "mkt-christ"
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f"  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge")
